sp_theme.css_variables:
/* 2.5.21 | 08.31.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed) */

#uiNotificationContainer { 
	z-index: 100000!important; 
}

//------------------------------------------------------------------------------------------------------------------------
// CLASSIFICATION
//------------------------------------------------------------------------------------------------------------------------

.taskform-classification-banner-Unclassified {
  background-color: #44835e;
  color:	 		white;
}

.taskform-classification-banner-Official {
  background-color: #2174AB; 
  color: 			white;
}

.taskform-classification-banner-Protected {
  /* 2.7.0 | 2021-08-07 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance */
  /* change color to a brown and add semicolon */
  /* background-color: #44835e */
  background-color: #795548;
  color: 			white;
}

.taskform-classification-banner-Restricted {
  background-color: #407d6f; 
  color: 			white;
}

.taskform-classification-banner-Secret {
  background-color: #E32921;
  color: 			white;
}

.taskform-classification-banner-Top.Secret {
  background-color: #FFCC00;
  color: 			#434343;
}






/* Banner Notification & Danger Dots */
//--------------------------------------------------------
$banner-count-bg: 				#E32921 !default; //danger
$banner-count-text: 			white !default;

/* To get service status messages consistent with brand colors */
//------------------------------------------------------------------------------------------------------------------------
$primary: 						$brand-primary;
$warning: 						$brand-warning;
$success: 						$brand-success;
$info: 							$brand-info;
$danger: 						$brand-danger;
$input-border-placeholder: 		white;


/* To get color boxes and count colors consistent with brand colors */
//------------------------------------------------------------------------------------------------------------------------
$brand-primary-text:			white !default;
$brand-warning-text:			#434343 !default;
$brand-success-text:			#434343 !default;
$brand-info-text:				white !default;
$brand-danger-text:				white !default;


/* Tasker States */
//--------------------------------------------------------
$state-disabled-bg: 			#dddddd !default;
$state-disabled-text: 			#434343 !default;

$state-new-bg: 					white !default;
$state-new-text: 				#434343 !default;

$state-waiting-bg: 				#6b6b6b !default;
$state-waiting-text: 			white !default;

$state-unassigned-bg: 			#F6C716 !default; //warning
$state-unassigned-text: 		#434343 !default;

$state-assigned-bg: 			#427A93 !default;
$state-assigned-text: 			white !default;

$state-accepted-bg: 			#A0D468 !default;
$state-accepted-text: 			#434343 !default;

$state-rejected-bg: 			#E32921 !default; //danger 
$state-rejected-text: 			white !default;

$state-workinprogress-bg: 		#2E3C54 !default; //primary
$state-workinprogress-text: 	white !default;

$state-workscheduled-bg: 		#2E3C54 !default; //primary
$state-workscheduled-text: 		white !default;

$state-inreview-bg: 			#736ac6 !default; //info
$state-inreview-text: 			white !default;

$state-rework-bg: 				#2E3C54 !default; //primary
$state-rework-text: 			white !default;

$state-completed-bg: 			#37C1C3 !default; //success
$state-completed-text: 			#434343 !default;

$state-closedincomplete-bg: 	#37C1C3 !default; //success
$state-closedincomplete-text:	#434343 !default;

$state-cancelled-bg: 			#37C1C3 !default; //success
$state-cancelled-text: 			#434343 !default;

/* Icons overrrides on Summary Card */
//--------------------------------------------------------
$icon-default-bg: 				#434343;


/* Tasker Data Table Selected Row */
//--------------------------------------------------------
$taskerdatatable-selected-row-bg: #B5DDE5; //#767676;
$taskerdatatable-selected-row-text:	#434343; //#fff;

/* Task List View */
//--------------------------------------------------------
$tasklistview-selected-border-right-bg: #ADD8E6;
$tasklistview-selected-bg: 		white;
$tasklistview-bg: 				#F5F5F5;


/* Alert overrides */
//--------------------------------------------------------
$state-danger-bg: lighten(saturate(adjust-hue($brand-danger, 354), 42.52%), 42.94);
$state-danger-border: $brand-danger;
$state-danger-text: darken(saturate(adjust-hue($brand-danger, 2), 1.25%), 25.10);
//$state-info-bg: lighten(desaturate($brand-info, 3.27%), 19.02);
//$state-info-border: $brand-info;
$state-info-text: #457e92; //darken(desaturate(adjust-hue($brand-info, 1), 2.75%), 41.57);
$state-success-bg: lighten(saturate($brand-success, 3.67%), 28.24);
$state-success-border: $brand-success;
$state-success-text: darken(desaturate(adjust-hue($brand-success, 3), 15.64%), 34.31);
$state-warning-bg: lighten(saturate(adjust-hue($brand-warning, -3), 17.70%), 29.61);
$state-warning-border: $brand-warning;
$state-warning-text: darken(desaturate(adjust-hue($brand-warning, -4), 20.32%), 44.31);

$alert-danger-bg: $state-danger-bg;
$alert-danger-border: $state-danger-border;
$alert-danger-text: $state-danger-text;
$alert-info-bg: white;
$alert-info-border: #5bc0de;
$alert-info-text: #407e91;
$alert-success-bg: $state-success-bg;
$alert-success-border: $state-success-border;
$alert-success-text: $state-success-text;
$alert-warning-bg: $state-warning-bg;
$alert-warning-border: $state-warning-border;
$alert-warning-text: $state-warning-text;


/* Error overrides */
//--------------------------------------------------------
.has-error .form-control {
	border-color: $state-danger-border!important;
}


/* Default */
//------------------------------------------------------------------------------------------------------------------------
$sp-logo-margin-x: 				15px !default;
$sp-tagline-color: 				$text-color !default;
$navbar-inverse-bg: 			#3a3f51 !default;
$navbar-inverse-link-color: 	#bdc0c4 !default;
$navbar-inverse-link-hover-color: #ffffff !default;
$body-bg: 						#f0f3f4 !default;
$dropdown-link-disabled-color: 	#ccc;
@media screen and (min-width: 768px) {
	.navbar-right .dropdown-menu {
		left: -10% !default;
		right: auto !default;
	}
}

/* 508 */
//------------------------------------------------------------------------------------------------------------------------
$accessible-placeholder-gray: 	#434343; //updated


[accessibility="true"] {
	a {
		&:hover {
			text-decoration: underline !default;
		}
		&:focus {
			text-decoration: underline !default;
		}
	}
	.sp-announcement-root {
		a {
			text-decoration: underline !default;
		}
	}
	[uib-rating] {
		.glyphicon-star {
			color: black !default;
		}
	}
	input::-webkit-input-placeholder {
		color: $accessible-placeholder-gray !default;
	}
	input::-moz-placeholder {
		color: $accessible-placeholder-gray !default;
	}
	input:-ms-input-placeholder {
		color: $accessible-placeholder-gray !default;
	}
}
